sys_script.script:
/**
 * Business Rule: Before check-in record is inserted
 * - Prevents duplicate check-ins for same user+venue+event
 */
(function checkinBeforeInsert(current, previous) {
    var existing = new GlideRecord('x_1838075_pub_cr_0_checkin');
    existing.addQuery('user', current.getValue('user'));
    existing.addQuery('venue', current.getValue('venue'));
    existing.addQuery('event', current.getValue('event'));
    existing.query();

    if (existing.hasNext()) {
        current.setAbortAction(true);
        gs.addErrorMessage('You have already checked in at this venue for this event');
    }
})(current, previous);
